import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import LanguageDetector from 'i18next-browser-languagedetector';

const resources = {
  en: {
    translation: {
      // General
      'appTitle': 'Wolt Discounts',
      'loading': 'Loading...',
      'error': 'Error loading data',
      'retry': 'Retry',
      'noDiscounts': 'No discounts available',
      'storeNotFound': 'Store not found',
      'searchStores': 'Search stores...',
      'noSearchResults': 'No stores found matching your search',

      // Stores
      'stores': 'Stores',
      'storesWithDiscounts': 'Stores with Discounts',
      'discountCount': 'Discount count',
      'avgDiscount': 'Avg. discount',
      'viewStore': 'View Store',
      'all': 'All',
      'supermarkets': 'Supermarkets',
      'pharmacies': 'Pharmacies',

      // Products
      'products': 'Products',
      'discountedProducts': 'Discounted Products',
      'currentPrice': 'Current price',
      'originalPrice': 'Original price',
      'discount': 'Discount',
      'category': 'Category',
      'openInWolt': 'Open in Wolt',
      'backToStores': 'Back to Stores',

      // Language
      'language': 'Language',
      'english': 'English',
      'russian': 'Russian',
    }
  },
  ru: {
    translation: {
      // General
      'appTitle': 'Скидочница',
      'loading': 'Загрузка...',
      'error': 'Ошибка загрузки данных',
      'retry': 'Повторить',
      'noDiscounts': 'Нет доступных скидок',
      'storeNotFound': 'Магазин не найден',
      'searchStores': 'Поиск магазинов...',
      'noSearchResults': 'Не найдено магазинов по вашему запросу',

      // Stores
      'stores': 'Магазины',
      'storesWithDiscounts': 'Магазины со скидками',
      'discountCount': 'Количество скидок',
      'avgDiscount': 'Средняя скидка',
      'viewStore': 'Просмотр магазина',
      'all': 'Все',
      'supermarkets': 'Супермаркеты',
      'pharmacies': 'Аптеки',

      // Products
      'products': 'Товары',
      'discountedProducts': 'Товары со скидкой',
      'currentPrice': 'Текущая цена',
      'originalPrice': 'Исходная цена',
      'discount': 'Скидка',
      'category': 'Категория',
      'openInWolt': 'Открыть в Wolt',
      'backToStores': 'Назад к магазинам',

      // Language
      'language': 'Язык',
      'english': 'Английский',
      'russian': 'Русский',
    }
  }
};

i18n
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    resources,
    fallbackLng: 'en',
    interpolation: {
      escapeValue: false,
    },
    detection: {
      order: ['localStorage', 'navigator'],
      caches: ['localStorage'],
    }
  });

export default i18n;
